#include <stdio.h>

static inline long long xor_upto(long long x) {
    switch (x & 3LL) {
        case 0: return x;
        case 1: return 1LL;
        case 2: return x + 1LL;
        default: return 0LL; // case 3
    }
}

static inline long long range_xor(long long l, long long r) {
    return xor_upto(r) ^ xor_upto(l - 1);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M, K; scanf("%lld %lld %lld", &N, &M, &K);
        long long base = K + 2; // because i and j start from 1
        long long ans = 0;
        for (long long x = 0; x < N; ++x) {
            long long L = base + x;
            long long R = L + M - 1;
            ans ^= range_xor(L, R);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

