code.Python3:
import sys

def xor_upto(x: int) -> int:
    r = x & 3
    if r == 0:
        return x
    if r == 1:
        return 1
    if r == 2:
        return x + 1
    return 0

def range_xor(l: int, r: int) -> int:
    return xor_upto(r) ^ xor_upto(l - 1)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        base = K + 2
        ans = 0
        for x in range(N):
            L = base + x
            R = L + M - 1
            ans ^= range_xor(L, R)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

